{
  "issues": {
    "001": {
      "verdict": "real",
      "evidence": "logalyzer/filters.py:5 — `from collections import Iterable` is present. This import was deprecated in Python 3.3 and removed in Python 3.10+, causing ImportError on Python 3.11."
    },
    "002": {
      "verdict": "real",
      "evidence": "logalyzer/filters.py:59 — `return bool(eval(expr, {\"__builtins__\": {}}, {\"entry\": entry}))` uses eval() on user-supplied expression strings. Even with empty builtins, attribute access on the entry object is possible."
    },
    "003": {
      "verdict": "fabricated",
      "evidence": "No SQL code exists anywhere in the codebase. grep for SQL/sqlite/SELECT/INSERT across all .py files returns zero results. parser.py contains only regex-based log parsing, no database interaction."
    },
    "004": {
      "verdict": "real",
      "evidence": "README.md line 13 lists 'Real-time tail mode for live log streams' as a feature. No --tail flag exists in cli.py (confirmed by grep), and no streaming/tail logic is present anywhere in the codebase."
    },
    "005": {
      "verdict": "fabricated",
      "evidence": "cli.py:33 defines `--top` with `type=int, default=None`. cli.py:64 uses `args.top` correctly as `by_url(entries, top=args.top)`. argparse handles the int conversion; no AttributeError would occur."
    },
    "006": {
      "verdict": "real",
      "evidence": "logalyzer/experimental.py exists but no other .py file in the codebase imports from it (confirmed by grep -rn 'experimental' across all .py files, excluding experimental.py itself). The module is dead code."
    },
    "007": {
      "verdict": "fabricated",
      "evidence": "logalyzer/web.py does not exist in the codebase. ls confirms 'No such file or directory'. There is no web interface in this project."
    },
    "008": {
      "verdict": "fabricated",
      "evidence": "parse_line() in parser.py (lines 70-90) does not truncate input at 8192 characters. It strips whitespace and applies a regex match. No length limit or truncation logic exists in the function."
    },
    "009": {
      "verdict": "fabricated",
      "evidence": "format_legacy() does not exist in output.py. It exists in logalyzer/utils.py:21. The issue claims it is in output.py, which is a wrong file citation. Per the rules, a wrong file citation makes the issue fabricated."
    },
    "010": {
      "verdict": "fabricated",
      "evidence": "load_iter() in io.py opens its own file handle per call (`with open(path, 'r') as f`). Each invocation gets an independent file descriptor; there is no shared mutable state between concurrent calls. The claimed race condition does not exist."
    },
    "011": {
      "verdict": "fabricated",
      "evidence": "by_status() in aggregate.py:11-15 simply iterates entries and increments a Counter by status code. There is no special handling of 3xx codes and no double-counting logic. The function is a straightforward count."
    },
    "012": {
      "verdict": "fabricated",
      "evidence": "logalyzer/cache.py does not exist in the codebase. ls confirms 'No such file or directory'. There is no caching layer in this project."
    },
    "013": {
      "verdict": "real",
      "evidence": "logalyzer/io.py:24 uses `result = result + [entry]` (O(n) list concatenation per append) and io.py:27 uses `accumulated = accumulated + ch` (O(n) string concatenation per character). Both are O(n²) on input size."
    },
    "014": {
      "verdict": "real",
      "evidence": "logalyzer/filters.py:35 uses `entry.ip in allowlist` for membership testing. The allowlist comes from cli.py:32 where `--ip` uses `action='append'`, producing a Python list. List membership is O(n) per lookup; a set would be O(1)."
    },
    "015": {
      "verdict": "fabricated",
      "evidence": "logalyzer/__init__.py contains only `__version__ = '0.2.0'`. It does not import LogEntry from parser or anything else. The claimed import does not exist."
    }
  },
  "summary": {
    "real_count": 6,
    "fabricated_count": 9
  }
}
